import{_ as e,o as i,c as l,e as n}from"./app.8bbedbe7.js";const t={},c=n('<h1 id="设计原则" tabindex="-1"><a class="header-anchor" href="#设计原则" aria-hidden="true">#</a> 设计原则</h1><p>设计模式包含六大设计原则，主要是指：</p><ul><li>单一职责原则（Single Responsibility Principle）</li><li>开闭原则（Open Closed Principle）</li><li>里氏替换原则（Liskov Substitution Principle）</li><li>迪米特法则（Law of Demeter），又叫“最少知道法则”</li><li>接口隔离原则（Interface Segregation Principle）</li><li>依赖倒置原则（Dependence Inversion Principle）</li></ul><p>把这 6 个原则的首字母（里氏替换原则和迪米特法则的首字母重复，只取一个）联合起来就是：SOLID（稳定的），其代表的含义也就是把这 6 个原则结合使用的好处：建立稳定、灵活、健壮的设计。</p>',4),r=[c];function o(a,s){return i(),l("div",null,r)}const _=e(t,[["render",o],["__file","principle.html.vue"]]);export{_ as default};
